964: // Simple ABI wrapper for initialize allocated memory.
965: export fn lex_state_init(state: *anyopaque) void {
966:     // Ensure the allocated memory is aligned.
967:     assert(@intFromPtr(state) % @alignOf(State) == 0);
968: 
969:     const s: *State = @ptrCast(@alignCast(state));
970:     s.init();
971: }
972: 
973: // Needed for the caller to allocate memory for our State.
974: export const lex_state_size: usize = @sizeOf(State);
975: 
976: // Needed for the caller to allocate memory for our State.
977: export const lex_state_alignment: usize = @alignOf(State);
